#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int arr[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    int max_len = 0;
    for (int i = 0; i < N; i++) {
        int prod = 1;
        for (int j = i; j < N; j++) {
            prod *= arr[j];
            if (prod != 0) {
                max_len = (j - i + 1) > max_len ? (j - i + 1) : max_len;
            }
        }
    }
    printf("%d\n", max_len);
    return 0;
}

