code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] arr = new int[N];
        for (int i = 0; i < N; i++) {
            arr[i] = sc.nextInt();
        }
        int max_len = 0;
        for (int i = 0; i < N; i++) {
            int prod = 1;
            for (int j = i; j < N; j++) {
                prod *= arr[j];
                if (prod != 0) {
                    max_len = Math.max(max_len, j - i + 1);
                }
            }
        }
        System.out.println(max_len);
    }
}

